var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하, 하나……! 둘……! 셋!","JPN":"い、いっち…！　にの…！　さんっ！","ENG":"O-one...! Two...! Three...!","TWN":"一……！二……！三！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"영차아!","JPN":"えいっ！","ENG":"Chaa!","TWN":"嘿咻！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"좋아. 우리가 부탁 받은 보급품은 이 컨테이너가 마지막이다.","JPN":"よし。俺たちが頼まれた補給品はこのコンテナで最後だ。","ENG":"All right. This is the last container of supplies we've been asked for.","TWN":"好了。這個貨櫃是我們奉命轉交的最後一件補給品。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아사는 나중에 걱정해도 되겠군. 이걸로 당장 급한 불은 끌 수 있겠어.","JPN":"これでしばらく飢え死ぬ心配はないな。差し迫った問題は解決しそうだ。","ENG":"That's one less thing to worry about for now. Not starving.","TWN":"暫時不用擔心會餓死的問題了。這些東西可以解決我們的燃眉之急。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"프리라이더 아가씨들도 수고했어.","JPN":"フリーライダーのお嬢ちゃんたちもご苦労様。","ENG":"Well done to you as well, Free Riders.","TWN":"免費騎士的二位小姐也辛苦了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"으으, 여기까지 와서도 노동에 시달려야 하다니…….","JPN":"うう、ここに来てまで労働で苦しまないといけないなんて……","ENG":"Ugh, I can’t believe we have to work our butts off in here too...","TWN":"呃呃呃……都到這裡了，居然還要做苦工……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"최첨단 함선에서 사람 손으로 짐을 날라야 하다니……. 너무 가혹한 현실이에요…….","JPN":"最先端の艦船なのに、人力で荷物を運ばなければならないなんて……あまりにも過酷な現実です……","ENG":"Moving supplies by hand in a state-of-the-art ship... It's too sad...","TWN":"在最先進的艦船上，居然還要靠人工來搬運……現實太殘酷了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"당분간은 참아. 허수공간을 탈출하기 전까진 절약할 수 있는 건 최대한 절약해야 해.","JPN":"しばらくは我慢して。虚数空間を抜け出すまではできるだけ節約しなければいけないわ。","ENG":"Suck it up for now. We have to save everything until we get out of the imaginary space.","TWN":"先忍忍。在逃出虛數空間之前，必須能省則省。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"예를 들어 기중기의 동력이라거나.","JPN":"クレーンの動力とかね。","ENG":"For instance, we should save the power for cranes and stuff.","TWN":"比如起重機的動力什麼的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"으음! 도움이 되지 못해 미안하군!","JPN":"うむ！　役に立てず申し訳ない！","ENG":"Mmh! I'm sorry to be of no help!","TWN":"呃嗯！很抱歉沒能幫上忙！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"할 수 있다면 내 포신에 줄이라도 달고 돕고 싶건만!","JPN":"できるものなら、吾輩の砲身に縄でもひっかけて助けたいところだが！","ENG":"I wish I could connect everything to my gun barrel!","TWN":"如果可以，我想在我的炮身上掛根繩子！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아휴, 정비하다 고막 터지겠는데요! 성량이 너무 커요!","JPN":"もう、整備中に鼓膜が破けちゃいそうなのです！　声が大きすぎなのです！","ENG":"Hey, you're going to blow my ears out! You're too loud!","TWN":"呀，我還在檢修呢！你的音量太大了！耳膜都要炸了啦！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L19_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"이러다 늦어지면 손해라니까요! 체르노바 소장님이 데이터 달라고 야단인데!","JPN":"これで遅れが出たらまずいのです！　チェルノワ所長がデータを渡せとうるさいんですから！","ENG":"Things are not going to be pretty if we run late! Director Chernova's waiting for the data!","TWN":"晚，晚了可不行！安娜斯塔莎所長吵著要數據呢！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하, 미안하네! 나 때문에 개장이 늦어지면 안 되지, 아무렴!","JPN":"はは、すまない！　吾輩のせいで改装が遅れては困る、うむ！","ENG":"Ha ha, my apologies! Well, the remodeling shouldn’t be delayed because of me!","TWN":"哈哈，對不起！不能因為我導致改裝推遲，當然！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"제길, 얼른 쫓아가도 모자랄 판국에 이런 데서 한가하게 뭐 하는 거야?","JPN":"クソ、早く追いかけなきゃいけないってときに、こんなところで何をぐずぐずしてんだよ？","ENG":"Damn it, what are we doing? Shouldn’t we be going after them?","TWN":"該死，我們現在是在幹什麼，怎麼還有工夫閒聊啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저 해적 녀석들은 왜 여기 나타난 거고?","JPN":"あの海賊どもは何でここに現れたんだ？","ENG":"And why are those pirates here?","TWN":"話說那群海盜為什麼會出現在這裡？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 섭섭하게 그 눈빛은 뭐야?","JPN":"おう、なんだその目つきは、悲しいな。","ENG":"Oh, what's with that face? You're hurting my feelings.","TWN":"噢，好傷心，你那是什麼眼神？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"기껏 허수공간까지 먹을 것 입을 것 쏴 재낄 것 바리바리 싸들고 온 사람들한테.","JPN":"せっかく虚数空間まで食べるモノ、着るモノ、撃ってぶっ放すモノ、色々持ってきてやったのに。","ENG":"We came all the way to the imaginary space to save you all from starvation and shortage.","TWN":"怎麼說我也是帶著吃的、穿的、用的來到虛數空間的人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"어차피 잠시 협력하는 관계에 불과하긴 하지.","JPN":"どうせ一時の協力関係に過ぎない。","ENG":"I guess this is just a temporary truce, though.","TWN":"反正我們也只是暫時合作的關係。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"다시 한 번 붙고 싶다면 언제든지 환영이다. 태스크포스.","JPN":"もう一度やり合いたいんなら、いつでも受けて立つぞ、タスクフォース。","ENG":"You're always welcome to another fight, TASKFORCE.","TWN":"想要再比一場的話，我們隨時奉陪，特遣勢力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그만해, 바보야. 여기서 싸워 봤자 득 될 것 하나도 없어.","JPN":"やめなさい、バカ。こんなところで喧嘩したって、何一つ良いことはないわ。","ENG":"Stop it, idiot. Fighting won't help with anything here.","TWN":"夠了，笨蛋。在這裡打架一點好處都沒有。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"그럼 저 자식들이랑 한가하게 점심이나 먹자고?","JPN":"じゃあ、あいつらと呑気に飯でも食ってろって言うのかよ？","ENG":"Then what? You want to have lunch and tea with them like buddies?","TWN":"難道還要和那些傢伙坐下來悠閒地吃午飯啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이러고 있어도 돼? 대장은 연락이 끊긴 뒤로 어떻게 됐는지도 모르는데…….","JPN":"こんなことしていていいのか？　隊長は連絡つかなくなってから、どうしてるかもわからないのに……","ENG":"Are you sure we're supposed to be doing this? We don't even know what happened to Cap, after the comms broke off...","TWN":"我們就只能這麼待著？隊長失去聯繫後也不知道怎麼樣了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"너, 너무 걱정하지 마.","JPN":"そ、そんなに心配しなくてもいいんじゃないかな。","ENG":"D-don't worry too much.","TWN":"別，別太擔心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대장은 괜찮을 거야……. 미나 씨랑 시윤 선배도 같이 있었잖아.","JPN":"隊長は大丈夫だと思うよ……ミナさんとアキヤマ先輩も一緒だったんだから。","ENG":"Cap will be okay... She had Mina and Shiyoon with her.","TWN":"隊長會沒事的……米娜和時雲前輩也和她在一起呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"쳇…….","JPN":"ちっ……","ENG":"Tsk...","TWN":"嘖……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"심정은 이해하지만 냉정하게 생각해.","JPN":"気持ちはわかるが、今は冷静に考えろ。","ENG":"I understand how you feel, but try to think rationally.","TWN":"我理解你們的心情，但是現在先冷靜地想一想。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"솔직히 지금은 우리 발등에 떨어진 불부터 끄는 게 먼저야.","JPN":"正直、今は目の前の問題を解決することが先決だ。","ENG":"We have to deal with the current situation first.","TWN":"現在我們要先解決燃眉之急是什麼。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"까짓 거 그냥 이판사판으로 공간 도약해 버리면 그만 아니야?","JPN":"そんなの、一か八かで空間跳躍しちまえばいいんじゃねえの？","ENG":"Can't we just try for the space jump? I mean, look at this mess.","TWN":"小意思，拼命用空間跳躍逃出去不就得了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그게 아가씨 말처럼 쉽지 않은 일이거든.","JPN":"お嬢ちゃん、それは言うほど簡単ではないんだ。","ENG":"It's easier said than done, Miss.","TWN":"這件事沒你說得那麼簡單。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……간단히 말해서, 허수공간은 관측자에 따라 매번 다르게 바뀌는 곳이야.","JPN":"……簡単に言えば、虚数空間は観測者ごとに毎回変化する場所。","ENG":"...Basically, the imaginary space is a place that's subjective to the observer.","TWN":"……簡單地說，在不同的觀測者眼裡，虛數空間也會變得不一樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"시간의 흐름부터 공간의 좌표까지.","JPN":"時間の流れから空間の座標までもがだ。","ENG":"From time itself to the coordinates of space.","TWN":"從時間的流逝到空間座標皆是如此。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 간극을 계산으로 좁힌다는 건 이론상에서나 가능한 일이야.","JPN":"その誤差を、計算で埋めるというのは理論上ならともかく、不可能なことなんだよ。","ENG":"Closing that distance through calculation is only possible in theory.","TWN":"透過計算來縮小這個差距，這件事只在理論上可行。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"함부로 공간 도약을 시도했다간 함선이 입자 단위로 분해되어 버릴 거다.","JPN":"無闇に空間跳躍を試そうものなら、艦船が粒子単位でバラバラになっちまう。","ENG":"If we aren't careful enough, this whole ship will be decomposed into mere particles.","TWN":"隨便嘗試空間跳躍的話，艦船會被分解成粒子單位。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야, 그럼 죽을 때까지 여기서 손 놓고 있자고?","JPN":"なんだよ、じゃあここで死ぬまでただ待ってろっていうのかよ？","ENG":"Then what? You want to relax here until we die?","TWN":"什麼嘛，那我們就什麼都不做，在這裡等死嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조금만 기다려. 스캐빈저 놈들도 무작정 여기 오진 않았을 거다.","JPN":"少し待ってみよう。スカベンジャーの連中も無策でここに来てはいないだろう。","ENG":"Not so fast. The Scavengers wouldn't have come unprepared.","TWN":"再等等。清道夫那些傢伙應該不會毫無準備地來到這裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"고심도에서 활동하던 녀석들이니 여기서 벗어날 무슨 비법이 있겠지.","JPN":"高深度で活動している連中だ。ここから抜け出せる方法も知っているにちがいない。","ENG":"They're used to roaming around in the hyperdepths. They probably know a way out of here.","TWN":"他們曾經在高深度異界活動，應該有什麼辦法可以離開這裡吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아니, 우린 그냥 두목이 시키는 대로 온 건데?","JPN":"いや、俺らはボスに言われて来ただけだぜ？","ENG":"Nope, we're just here because Boss told us to.","TWN":"沒有欸，我們只是單純聽老大的話就過來了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"스캐빈저는 강자가 모든 것을 지배한다.","JPN":"スカベンジャーは強者がすべてを支配する。","ENG":"The strong rule over everything among the Scavengers.","TWN":"清道夫是由強者統治一切。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"목숨도 예외는 아니지.","JPN":"命だって例外じゃない。","ENG":"That includes life and death.","TWN":"性命也不例外。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 아무 대책 없이 넙죽 왔다는 거냐, 너희들은?!","JPN":"じゃあ何の対策もなく来たってのか、お前たちは！？","ENG":"So you just came here without thinking?!","TWN":"所以你們什麼對策都沒有就跑過來了啊？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"……들었지? 이번엔 진짜 잘못 엮인 것 같은데?","JPN":"……聞いただろ？　今回は選ぶ仕事を間違ったみたいだな？","ENG":"...Hear that? I think we got ourselves into big trouble this time.","TWN":"……聽到了吧？這次可真的麻煩了呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"어쩌지. 이럴 줄 알았으면 차라리 공간 도약 하기 전에 뛰어내렸을 텐데…….","JPN":"参ったな。こうなるとわかってたら空間跳躍する前に飛び降りてたのによ……","ENG":"What should we do? I should have just jumped off before the space jump...","TWN":"怎麼辦？早知道這樣，說什麼也要在空間跳躍前跳下船……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭘 겁쟁이처럼 벌벌 떨고 있어?","JPN":"何腰抜けみたいに怖がってんだよ？","ENG":"What are you cowering about?","TWN":"你幹嘛像個膽小鬼似的瑟瑟發抖？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"우리가 누구냐? 테라사이드 전역에서도 살아남은 역전의 베테랑들이라고!","JPN":"俺たちは誰だ？　テラサイド戦域でも生き延びた、歴戦のベテランじゃねえか！","ENG":"Did you forget who we are? We’re veterans! We survived the Terraside battle!","TWN":"我們是誰啊？我們可是在特拉賽德戰役中也活下來的逆轉老兵！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"……뒷걸음질 치면서 그렇게 말해도 말이야.","JPN":"……後ずさりしながらそんなこと言われてもな。","ENG":"...It's not so convincing if you say it while backing away, you know.","TWN":"……說這些話的時候你倒是別後退啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"어어, 잠깐! 발밑 조심해!","JPN":"おい、待て！　足元に気を付けろ！","ENG":"Hey, wait! Look out below!","TWN":"噢噢，等等！小心腳下！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"우오오?!","JPN":"うおお！？","ENG":"Uaah?!","TWN":"唔噢噢？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"괜찮아, 토미?","JPN":"大丈夫か？　トミー？","ENG":"You okay, Tommy?","TWN":"你沒事吧，湯米？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그러길래 조심하라고 했잖아.","JPN":"だから気をつけろって言ったのに。","ENG":"I told you to be careful.","TWN":"我就知道會這樣才叫你小心點。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"끄으응…….","JPN":"ぐぬぅ……","ENG":"Nnngh...","TWN":"呃呃呃……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 무슨 일이지?","JPN":"おい、どうした？","ENG":"Hey, what's going on?","TWN":"喂，發生什麼事了？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이 녀석이 화물에 발이 걸려 넘어졌어.","JPN":"こいつが貨物に足引っかけてコケたんだ。","ENG":"He slipped and fell over some cargo.","TWN":"這傢伙被貨物給絆倒了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그래. 그래. 나 같은 통뼈가 아니었으면 엉덩이가 쪼개졌을걸.","JPN":"そう、そう。俺みたいな骨太じゃなかったらお尻が割れているところだぞ。","ENG":"Yeah, yeah. My butt would’ve cracked open if I wasn't so sturdy.","TWN":"是啊，要不是我身體結實，屁股早就摔成二半了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그걸 자랑이라고 하냐. 사방에 온통 탄약에 폭발물이니까 조심하라고……","JPN":"自慢することか。周りは弾薬やら爆発物やらばかりだ、気を付けろよ……","ENG":"Congratulations, fool. Be extra careful, we're surrounded by explosives–","TWN":"你這是在炫耀嗎？這裡堆著的都是彈藥和爆裂物，你小心點……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":" 응?","JPN":" ん？","ENG":" Huh?","TWN":" 嗯？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"혹시 걸려 넘어졌다는 게 이 케이스인 건가?","JPN":"もしかして引っかかったてのは、このケースか？","ENG":"Is this the case that you fell over?","TWN":"你是被這個盒子絆倒的？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아, 맞아. 그거야.","JPN":"おお、そう。それだ。","ENG":"Oh, yeah. That's it.","TWN":"啊，沒錯，就是它。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"모양이 좀 특이한데. 군용 화물 같지는 않아.","JPN":"ちょっと変わった形をしているな。軍用貨物ではなさそうだ。","ENG":"Rather strange looking. It doesn't look like military cargo.","TWN":"形狀有點特別呢，不像是軍用貨物。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"식별표는 안 붙어 있고, 이름이……","JPN":"識別表はついていない、名前は……","ENG":"There's no ID tag on it, and the name...","TWN":"上面也沒貼標籤，名字是……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"M 패키지? 뭐 하는 물건이지?","JPN":"Mパッケージ？　どういう代物だ？","ENG":"M Package? What is this?","TWN":"M包？這是什麼東西？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"무슨 문제라도 생겼나요? 굉장히 큰 소리가 들리던데.","JPN":"どうしましたか？　すごく大きな音がしましたが。","ENG":"Is everything okay? I heard a loud noise.","TWN":"出了什麼問題嗎？我聽到了巨響。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 마침 잘 왔어. 저격수 아가씨.","JPN":"おお、いいところに来たな。スナイパーのお嬢ちゃん。","ENG":"Oh, there you are. Miss Sniper.","TWN":"啊，你來得正好，狙擊手小姐。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"혹시 이 케이스 뭔지 알겠나? 그쪽에서 가져 온 것 같은데?","JPN":"このケースが何か知っているか？　そっちの荷物だと思うんだが？","ENG":"Do you have any idea what this is? It looks like something you brought.","TWN":"你知道這個盒子是什麼嗎？好像是你們拿過來的？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그게, 저희 쪽에서 가져 온 게 맞는 것 같은데…….","JPN":"うーんそれが、私たちの荷物だとは思いますが……","ENG":"Um, I think it's one of our belongings, but...","TWN":"這個，好像是我們拿過來的沒錯……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"잘은 모르겠어요. 엔터프라이즈로 옮겨 탈 때는 다들 정신이 없었거든요.","JPN":"よくわかりません。エンタープライズに乗り移るときは、みんなそれだけで忙しかったので。","ENG":"I'm not so sure. Everything was so hectic when we moved to the Enterprise.","TWN":"我也不清楚，搬到企業號上時大家都很匆忙。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"앗! 혹시 안에 굉장히 비싼 무기 같은 게 들어 있는 거 아니에요?","JPN":"あっ！　ひょっとして中にすごく高価な武器とかが入ってるんじゃないですかね？","ENG":"Ah! Maybe there’s a super cool weapon inside!","TWN":"啊！難道這裡面裝了什麼秘密武器之類的？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"모양도 특이하고……. 어쩌면 던전에서 찾은 보물 상자일지도…….","JPN":"形も変わっているし……もしかしたらダンジョンで見つけた宝箱なのかも……","ENG":"It looks strange... Perhaps a treasure chest from one of the dungeons...?","TWN":"形狀也很特別……說不定是從副本裡找到的寶箱……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"글쎄. 하지만 나도 뭔지 모를 물건을 격납고에 두긴 좀 찜찜하군.","JPN":"さあな。でもこの得体の知れない物を格納庫に入れておくのは少々不安だ。","ENG":"I don't know. But I don’t feel comfortable leaving it in the hangar.","TWN":"不好說。不過把這種不知道是什麼的東西留在機庫裡，總覺得有點不放心。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그래. 얼른 눈에 안 띄는 데로 치워 버리자. 무슨 관짝처럼 생겼잖아.","JPN":"そうだな。早く目立たないところに移そう。棺桶みたいな形しているし。","ENG":"You're right. Let's put it somewhere we can’t see. It looks like a coffin, for goodness sake.","TWN":"真是的。趕緊收到看不見的地方吧。長得像棺材一樣。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"기분 나쁜 소리 하지 마. 그 정신없는 상황에 뭐하러 관짝을 맡겨?","JPN":"不気味なこと言うなよ。あんな余裕のない状況で棺桶なんか積むか？","ENG":"Stop creeping me out. Why would anyone want to move a coffin in that situation?","TWN":"少在那邊說不吉利的話！這種時候搬棺材要幹嘛？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"뭘 그렇게 쑥덕거리고 있나? 궁금하면 확인해 봐야지.","JPN":"何コソコソ話しているんだ？　気になるなら確認してみろよ。","ENG":"What are you all rambling about? If there's a conundrum, then all we have to do is solve it!","TWN":"你們在這裡嘀咕什麼呢？好奇的話打開看看不就好了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어라, 이건 플라즈마 절단기잖아? 언제부터 내 손에 들고 있었지?","JPN":"おやあ？　ここにプラズマ切断機があるぞ？　いつから手に持っていたんだろうなあ？","ENG":"Ah? Look, a plasma cutter! I have no idea why I'm holding it.","TWN":"哇喔，這不是等離子切割機嘛？什麼時候拿到我手裡的？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아, 그래. 맞아, 오른손아. 원래 닫힌 건 열라고 있는 거야.","JPN":"ああ、そうだよな、右手よ。閉ざされているものは開けるためにあるに決まってる。","ENG":"Oh, listen! My right hand says... \\"Closed things are meant to be opened.\\"","TWN":"啊，是啊，沒錯，我的右手在說，“關著的盒子本來就是用來打開的啊”。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐? 우리 회사 걸 너네가 뭐라고 마음대로 열어 봐?","JPN":"おい。何勝手にうちの会社の荷物、開けようとしてんだよ？","ENG":"Ah? Who gave you the right to open what's ours?","TWN":"蛤？我們公司的東西，你們憑什麼隨便打開？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그러게. 아무래도 제 버릇은 못 버리나 보네.","JPN":"本当。習慣って怖いわね。","ENG":"I know, right? Talk about past habits.","TWN":"就是說，真是狗改不了吃屎。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"해적이 해적질하겠다는데 너무한 거 아니야, 친구들?","JPN":"海賊が海賊らしいことをやろうとしているだけなのに何が悪いって言うんだ、お前たち？","ENG":"Hey, hey. Give us some slack here, we're merely doing what we do, as pirates.","TWN":"喂，喂，我們只是在做海盜該做的事而已，你們是不是太過分了，朋友們？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"우린 그냥 직업 윤리에 충실할 뿐이라고, 히히.","JPN":"俺らは職業倫理に充実なだけだぜ、へへ。","ENG":"We are devoted to our jobs, after all. He he!","TWN":"我們只是很敬業而已，嘻嘻。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"아니. 오히려 잘됐어.","JPN":"いや。でかしたぞ、ラウル。","ENG":"No. You did the right thing.","TWN":"不，這樣反而更好。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"다이브를 자주 해서 몸도 찌뿌둥하던 참이었다. 처음부터 그렇게 나왔어야지.","JPN":"ダイブ続きで身体もなまってたところだったんだ。最初からそうこなくっちゃな。","ENG":"I was starting to feel itchy from all that diving. We should have done this sooner.","TWN":"身體也正因為頻繁躍入感到不舒服呢，一開始就應該這樣。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"모두가 궁지에 처한 상황에서 기어코 분란을 일으킬 작정인가?","JPN":"全員がピンチだというのに、面倒事まで起こすつもりなのか？","ENG":"Are you really planning on causing chaos in this situation?","TWN":"如今正是處境艱難的時候，你們執意要鬧事嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자네들이 싸우겠다면 나도 가만히 있지는 않겠네.","JPN":"君たちが争うというなら、吾輩もじっとしてはいない。","ENG":"If you are going to fight, I will not just stand and watch.","TWN":"如果你們要打架，那我也不會袖手旁觀。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"오리지널 타이탄. 그렇지 않아도 성능이 궁금했지.","JPN":"オリジナルのタイタンか。ちょうどその性能が知りたかったんだ。","ENG":"The original Titan. I always wondered what you were truly capable of.","TWN":"是原型泰坦啊，我正好想知道你的性能如何呢。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"판에 끼겠다면 얼마든지 환영이다.","JPN":"お前もやるっていうなら、いくらでも歓迎する。","ENG":"You're always welcome to join the brawl.","TWN":"如果你想插上一腳，我們隨時歡迎。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그쪽 격납고가 소란스러워졌군, 로조.","JPN":"そっちの格納庫が騒がしいな、ロッゾ。","ENG":"I hear noise from your end, Rojo.","TWN":"機庫那邊怎麼這麼熱鬧，羅梭？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"무슨 일이지. 충돌은 피하라고 했을 텐데.","JPN":"いったいどういうことだ。揉め事は避けろと言ったはずだが。","ENG":"What's going on? I thought I made it clear to stay out of trouble.","TWN":"發生什麼事了，我說過要你們避免衝突吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음……? 이 목소리는……?","JPN":"うん……？　この声は……？","ENG":"Hm? This voice...","TWN":"嗯……？這聲音是……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L33_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"리, 린…… 의뢰할 때 봤던 그 커다란 로봇인가 봐.","JPN":"り、リン……あの依頼の時の大きなロボットだよ。","ENG":"L-Lin... It must be the gigantic robot we saw from that job we did.","TWN":"曉琳，曉琳……好像是那次委託時見過的那個巨型機器人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"……떨지 마. 리액터가 있는 이상 그 때처럼 무력하게 당하진 않을 거야.","JPN":"……落ち着いて。リアクターがある限り、あの時のように何もできずにやられることはないわ。","ENG":"...Don't panic. With the reactor, we won't lose easily like last time.","TWN":"……別害怕。我們有電抗器，不會像那時那樣被動挨打了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"보이나, 두목? 지금 막 두목이 흥미를 가질 만한 물건을 발견한 참이다.","JPN":"見えるか、ボス？　ちょうど今ボスが気に入りそうなモノを発見したところなんだ。","ENG":"You see, Boss? We just found something that might spark your interest.","TWN":"你也看到了吧，老大？剛才我們正好發現了一個老大會感興趣的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"지뢰찾기나 돌리면서 기다리고 있으라고!","JPN":"マインスイーパーでもして待ってろよ！","ENG":"Sit back and relax! Play Minesweeper until we come back.","TWN":"你就邊玩踩地雷邊等著吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"안에 어떤 보물이 있는지 금방 확인하고 가져갈 테니까!","JPN":"中にどんな宝物が入ってるか、すぐに確認して持っていくからよ！","ENG":"We'll check what kind of treasure is inside and return!","TWN":"等我們確認完裡面裝了什麼寶貝就帶回去！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"아니. 그 관은 저들에게 맡겨라.","JPN":"いや。その棺桶はあの者たちに任せておけ。","ENG":"No. Leave the coffin to them.","TWN":"不用，把那個棺材交給他們。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L44_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"두목이 참을성도 발휘하고 웬일이래? 오늘 아침에 항공유 마셨어?","JPN":"ボスが我慢をするなんていったいどうしたんだ？　今朝航空油でも飲んだのか？","ENG":"What's wrong with you, being patient all of a sudden? Did you drink the wrong oil this morning?","TWN":"老大變啦？這是怎麼回事？今天早晨喝錯油了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"저것에 대해 뭔가 알고 있는 건가?","JPN":"あれについて何か知っているのか？","ENG":"You know something about that thing, don't you?","TWN":"還是老大知道那是什麼東西？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>냉장고</color>.","JPN":"<color=#ffd34c>冷蔵庫</color>。","ENG":"<color=#ffd34c>Refrigerator</color>.","TWN":"“<color=#ffd34c>冰箱</color>”。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L48_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"과거 퓨처 앳 워가 입수했던 콜드 케이스 중 하나다.","JPN":"過去にフューチャーアットウォーが入手したコールドケースの一つだ。","ENG":"It is one of the cold cases that Future-at-War had acquired.","TWN":"過去天啟兵器得到的Cold Case之一。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"뭔가 잘못 안 거 아냐, 두목? 생긴 건 냉장고가 아니라 관짝인데?","JPN":"見間違えなんじゃないか、ボス？　冷蔵庫というよりは棺桶みたいな形だぞ？","ENG":"What do you mean, Boss? That's a coffin, not a fridge.","TWN":"你沒弄錯吧，老大？這東西長得不像冰箱，倒像是個棺材呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"외부에 유출되었을 때 정보를 왜곡시키기 위한 이름이다.","JPN":"外部に流出したときのために情報を歪曲させるための名称だ。","ENG":"It is a code name to distort information in case it was leaked.","TWN":"代號而已，在資訊洩露時混淆視聽用的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L1_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이름만 들어서는 피자 따위나 만드는 물건으로 착각하게 되지.","JPN":"名称だけだと、ピザを作る機械か何かと勘違いする。","ENG":"So that people will perceive it as nothing but junk that makes pizza.","TWN":"光聽名字，就會誤以為是放披薩什麼的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 지금의 나에게는 무가치한 것이다.","JPN":"そして、今の私にそれは無価値なものだ。","ENG":"Either way, that thing won't be of any use to me for now.","TWN":"而且，那個對現在的我來說毫無價值。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"가치 있는 것은 그 안에서 완성될 내용물이지.","JPN":"価値があるとすれば、その中で完成されるであろう中身。","ENG":"The real value lies in the object that will be completed within that thing.","TWN":"真正有價值的是那裡面即將完成的東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"중요한 샘플이다. 부적절한 변인을 제공하지 마라.","JPN":"重要なサンプルだ。不適切な要因を与えるな。","ENG":"It is a crucial sample. Do not cause any unnecessary variables.","TWN":"是個重要的樣本。不要再造成任何不必要的變數了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"흐음……. 그렇단 말이지.","JPN":"ふむ……なるほど。","ENG":"Hmm... I see.","TWN":"嗯……這樣啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어디 가, 깡통?","JPN":"何処に行くんだ、ボロ缶？","ENG":"Where do you think you're going, Tin Can?","TWN":"喂，你要去哪，鐵桶？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"복귀해야지. 여기서 우리가 할 일은 끝났다.","JPN":"復帰する。ここでの俺たちの仕事は終えた。","ENG":"I'm heading back. Our job here is done.","TWN":"當然是回去了。這裡我們能做的事已經都做完了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"에이, 기껏 재미 좀 보나 했더니 말이야. 분위기 읽을 줄 아는 사람은 나뿐인가?","JPN":"ちっ、せっかく楽しくなるところだったってのによ。空気が読めるのは俺だけなのか？","ENG":"Tsk, and here I was, thinking I was about to have some fun. Am I the only one here who can read the room?","TWN":"欸，我還以為會有點意思呢。就只有我一個人能讀懂氣氛嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"기다려, 깡통! 나도 같이 가!","JPN":"待てよ、ボロ缶！　俺も行く！","ENG":"Slow down, Tin Can! Wait for me!","TWN":"喂，等等我，鐵桶！我也一起走！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"휴, 휴우……. 이유는 모르겠지만 살았나 봐…….","JPN":"ふ、ふう……よくわからないけど助かったようね……","ENG":"P-phew... I don't know what just happened, but we survived...","TWN":"呼，呼……雖然不知道原因，但看來是活下來了……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌다 해적들하고까지 엮이게 됐을까요……. 이런 레벨 디자인 너무 싫어…….","JPN":"どうして海賊と関わることになったんでしょうか……こういうレベルデザインは本当に嫌です……","ENG":"How did we get involved with pirates... I hate this kind of level design...","TWN":"怎麼會和海盜攪和到一塊呢……太討厭這種關卡設計了……"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"쳇, 덤볐으면 혼쭐을 내 줬는데.","JPN":"ちっ、攻撃されたらやり返すつもりだったんだけどな。","ENG":"Tsk, I would have beaten them up if they tried anything.","TWN":"嘖，敢動手的話就教訓他們了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"자, 잘 참은 거야. 유진아.","JPN":"が、我慢して正解だったよ。シロコ。","ENG":"Y-you did well not provoking them, Eujin.","TWN":"嗯，你忍得很好，劉珍。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그 말이 맞아. 이런 일로 미리 힘을 뺄 필요는 없어.","JPN":"そうよ。こんなことで無駄に体力を使う必要はないわ。","ENG":"She's right. There's no need to waste energy on things like this.","TWN":"你說的沒錯。沒必要因為這種事而浪費力氣。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 저 녀석들, 반응이 좀 이상하더군.","JPN":"でもあいつら、少し様子が変だったな。","ENG":"But those pirates, they did react a bit strangely...","TWN":"不過那些傢伙，反應有點奇怪。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"콜드 케이스라는 것도…… 어디서 들어 봤는데.","JPN":"ゴールドケースというのも……聞き覚えがある。","ENG":"Cold case... I think I heard of it somewhere.","TWN":"Cold Case這個名字……我也在哪裡聽過。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"퓨처 앳 워 프로젝트에서 연구했던 아티팩트일 걸세.","JPN":"フューチャーアットウォープロジェクトで研究していたアーティファクトだろう。","ENG":"I assume it's an Artifact that Future-at-War had been researching on.","TWN":"是天啟兵器計畫中研究的人造神器。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아티팩트라고?","JPN":"アーティファクトだと？","ENG":"Artifact?","TWN":"人造神器？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음. 내 부품들 몇몇은 그것들을 연구하는 과정에서 나온 산물이라더군.","JPN":"うむ。吾輩に使われている部品の一部も、そられを研究する過程で得られた副産物だそうだ。","ENG":"Mmm. Some of my parts come from the process of studying it.","TWN":"沒錯，我身上的一些零件就是在研究的過程中製造出來的產物。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L32_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아티팩트라……. 이제 보니 처치 곤란한 물건이었네.","JPN":"アーティファクトか……そんな大層な物だったわけね。","ENG":"Artifact... This is far more of a predicament than I thought it would be.","TWN":"人造神器……現在看來，這東西很難處理呢。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아쉽지만 지금은 이대로 두는 수밖에 없겠군.","JPN":"残念だが、今はこのまま置いておくしかなさそうだ。","ENG":"I know we have a lot of questions, but for now, it's best that we leave it be.","TWN":"可惜現在只能這樣了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭐? 그게 정말이야?","JPN":"え？　本当に？","ENG":"What? Really?","TWN":"什麼？真的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"파악 안 된 아티팩트를 함부로 건드리는 건 자살 행위야.","JPN":"正体がわかっていないアーティファクトに下手に触るのは自殺行為だ。","ENG":"Touching an unidentified Artifact is suicide.","TWN":"隨便接觸尚未掌握的人造神器是自殺行為。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"문제가 터지면 손쓸 방법이 없을지도 몰라. 그러니까 고정용 로프나 가져오라고.","JPN":"問題が起きたとき、お手上げになる可能性もある。だからほら、固定用のロープでも持ってこい。","ENG":"We might not be able to stop whatever happens from messing with it. So go and fetch me ropes instead.","TWN":"不過為了避免出什麼問題……還是拿固定繩過來吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"휴우…… 그래도 싸우지 않고 잘 끝났나 본데요.","JPN":"ふう……でも、戦闘にはならずに済んだようですね。","ENG":"Phew... That ended well. At least they didn’t fight each other.","TWN":"呼……看來是沒有打起來，順利地結束了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"그럼 얼른 개장을 끝낼게요! 소장님이 주신 설계도면대로만 하면 되니까요!","JPN":"じゃあ改装を済ませてしまうのです！　所長からいただいた設計図通りにやればいいだけですので！","ENG":"I'll finish the remodeling soon, then! All that's left is to do what's on the blueprint that the Chief gave us!","TWN":"那我會儘快完成改裝！按照所長給的設計圖紙改就行！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"앗! 혹시 성량이 너무 크다고 해서 풀죽으신 건 아니죠?!","JPN":"あっ！　もしかして声量のことを言われて拗ねてますか！？","ENG":"Ah! I hope you're not frustrated because of the loud voice!","TWN":"啊！你不是因為我說你嗓門大就垂頭喪氣吧？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"그것도 매력 중의 하나라고 생각하는데요!","JPN":"それも魅力のうちだと思うのです！","ENG":"I consider it one of my charms!","TWN":"我認為那也是你的魅力之一！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"아니. 그것 때문은 아니다.","JPN":"いや、そういうことではない。","ENG":"No. It's not that.","TWN":"不，不是因為那個。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 통신으로 들렸던 그 목소리는…….","JPN":"さっき通信から聞こえたあの声は…","ENG":"But the voice from the comms...","TWN":"從通訊中聽到的那個聲音……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"마이크의 오류인가? 아니면…….","JPN":"マイクの問題でそう聞こえただけなのか？　それとも……","ENG":"Was it a mic problem? Or...","TWN":"是麥克風的問題嗎？還是說……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};